var brokerGateway = global.get("GWName");
var MQTTTempl = { "topic": "lnIn", "payload": { "From": brokerGateway, "ReqID": 0, "ErrorFlags": 16, "MsgType": "LN", "Valid": 1, "Data": []}};
var inpStr = msg.payload;
var outMsg = [];



function procSubStr(msgpart)
{
  const cleanStr = msgpart.trim().replace("/n", '').replace("/r", '');
  var msgArray = cleanStr.split(" ");
  if (msgArray.length > 0)
    switch (msgArray[0])
    {
      case "RECEIVE":
      {
        var newMsg = JSON.parse(JSON.stringify(MQTTTempl));
        for (var i = 1; i < msgArray.length; i++)
        {
          newMsg.payload.Data.push(parseInt(msgArray[i],16));
        }
        if (newMsg.payload.Data[0] == 0xB4)
        {
          var reqID = global.get("ReqID");
          if (reqID != undefined)
            newMsg.payload.ReqID = reqID;
        }
//        node.warn(newMsg);
        outMsg.push(newMsg);
      }
      break;
      default: return null;
    }
  return null;
}

var currTime = Date.now()/1000;
global.set("lastMsg", currTime);

var subStrStart = 0;
var subStrEnd = inpStr.indexOf("\n", subStrStart);
while (subStrEnd >= 0)
{
    procSubStr(inpStr.substring(subStrStart, subStrEnd + 1));
    subStrStart = subStrEnd + 1;
    subStrEnd = inpStr.indexOf("\n", subStrStart);
}
//node.warn("EOF");
//node.warn(outMsg);
return [outMsg];

const msgtimeout = 60;
const repeattimeout = 45;

if (msg.topic == "ticker")
{
    var currTime = Date.now()/1000;
    var lastTime = global.get("lastMsg");
    if ((currTime - lastTime) > msgtimeout)
    {
        var tcpMsg = {"topic":"totcp", "payload" : ""};
        var msgStr = "SEND BB 7B 00 3F";
        tcpMsg.payload = msgStr + "\n";
        global.set("lastMsg", currTime - repeattimeout);
        return tcpMsg;
    }
}

return null;

